from google.cloud import bigquery
from google.cloud import datacatalog

class TenantValidator:
    def __init__(self, tenant_id: str, schema_registry: datacatalog.DataCatalogClient):
        self.tenant_id = tenant_id
        self.schema_registry = schema_registry
        self.client = bigquery.Client()

    def load_schema(self) -> dict:
        scope = datacatalog.SearchCatalogRequest scope=datacatalog.EntryScope.GCP_RESOURCES)
        entry = self.schema_registry.search_catalog(
            request=datacatalog.SearchCatalogRequest(
                query=f"schema:{self.tenant_id}",
                scope=scope
            )
        )[0]
        return self._parse_schema(entry.linked_resources[0])

    def validate(self, record: dict) -> tuple[bool, list[str]]:
        schema = self.load_schema()
        errors = []
        for field, rules in schema.items():
            value = record.get(field)
            if rules.get('required') and value is None:
                errors.append(f"Missing required field: {field}")
            if value is not None and rules.get('type') == 'number':
                if not isinstance(value, (int, float)):
                    errors.append(f"Invalid type for {field}")
            if 'min' in rules and value < rules['min']:
                errors.append(f"Value {value} below minimum {rules['min']}")
            if 'max' in rules and value > rules['max']:
                errors.append(f"Value {value} above maximum {rules['max']}")
        return len(errors) == 0, errors
```

