function maskValue(value, type) {
  switch (type) {
    case 'hash': return crypto.createHash('sha256').update(value).digest('hex');
    case 'redact': return '[REDACTED]';
    case 'partial': return value.slice(0, 2) + '***';
    default: return value;
  }
}
