class ValidateEvent(beam.DoFn):
    def process(self, element, tenant_schemas):
        try:
            event = json.loads(element)
            tenant = event.get('tenant_id')
            schema = tenant_schemas.get(tenant)

            if not schema:
                yield beam.pvalue.TaggedOutput('quarantine', {
