                'raw': element, 'error': f'invalid_json: {e}',
                'tenant_id': None, 'ts': datetime.utcnow()
            })
        except ValidationError as e:
            yield beam.pvalue.TaggedOutput('quarantine', {
                'raw': element, 'error': f'schema_violation: {e.message}',
                'tenant_id': tenant, 'ts': datetime.utcnow()
