// Pseudocode: drift check between source and canonical schemas
function checkDrift(sourceSchema, canonicalSchema) {
  const drift = {
    added: [],
    removed: [],
    typeChanged: []
  };

  for (const field of sourceSchema.fields) {
    const canonicalField = canonicalSchema.fields[field.name];
    if (!canonicalField) {
      drift.added.push(field);
    } else if (field.type !== canonicalField.type) {
      drift.typeChanged.push({ field: field.name, expected: canonicalField.type, actual: field.type });
    }
  }

  for (const field of canonicalSchema.fields) {
    if (!sourceSchema.fields[field.name]) {
      drift.removed.push(field);
    }
  }

  return drift;
}

