function handleDrift(drift, tenantId) {
  if (drift.added.length > 0 || drift.removed.length > 0 || drift.typeChanged.length > 0) {
    sendAlert({
      tenantId,
      severity: 'HIGH',
      message: `Schema drift detected: ${JSON.stringify(drift)}`,
