```python
# Dataflow pipeline skeleton with contract validation

class MultiTenantPipeline(Pipeline):
    def __init__(self, project, region, schema_registry):
        self.project = project
        self.region = region
        self.schema_registry = schema_registry

    def build_pipeline(self, input_subscription, output_path):
        return (
            pipeline
            | 'ReadFromPubSub' >> ReadFromPubSub(subscription=input_subscription)
            | 'ValidateAgainstSchema' >> ParDo(SchemaValidationDoFn(self.schema_registry))
            | 'EnrichWithTenantContext' >> ParDo(TenantEnrichmentDoFn())
            | 'WriteToGCS' >> WriteToParquet(output_path)
        )

class SchemaValidationDoFn(DoFn):
    def __init__(self, schema_registry):
        self.schema_registry = schema_registry

    def process(self, element):
        tenant_id = element.get('tenant_id')
        schema = self.schema_registry.get_schema(tenant_id)
        try:
            validated = schema.validate(element)
            yield pvalue.TaggedOutput('valid', validated)
        except Exception as e:
            yield pvalue.TaggedOutput('invalid', (element, str(e)))

class TenantEnrichmentDoFn(DoFn):
    def process(self, element):
        element['processed_timestamp'] = datetime.utcnow().isoformat()
        element['region'] = self.region
        yield element
```

